import{_ as a,o,c as i,ag as t}from"./chunks/framework.NIzFHKo_.js";const h=JSON.parse('{"title":"ADR-0004: Single-Account Modular Mode","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/10_governance/50_decisions/adr-0004_single_account_modular_mode.md","filePath":"10_core/10_governance/50_decisions/adr-0004_single_account_modular_mode.md"}'),r={name:"10_core/10_governance/50_decisions/adr-0004_single_account_modular_mode.md"};function n(l,e,s,d,c,u){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-0004-single-account-modular-mode" tabindex="-1">ADR-0004: Single-Account Modular Mode <a class="header-anchor" href="#adr-0004-single-account-modular-mode" aria-label="Permalink to &quot;ADR-0004: Single-Account Modular Mode&quot;">​</a></h1><p>Date: 2026-04-04 Status: Proposed</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>QiOS v0.4 currently defines a Platform layer centered on multi-tenancy through the <code>qione</code> schema, including <code>tenants</code>, <code>tenant_members</code>, <code>member_roles</code>, <code>tenant_modules</code>, and <code>module_role_access</code>.</p><p>That model is valid for a hosted multi-tenant portal, but it adds significant implementation overhead for the current runtime goal: a standard authenticated app with strict per-user isolation and incremental module growth.</p><p>The current system does not require organization containers, cross-user shared workspaces, tenant billing, or tenant-scoped administration in order to deliver the first working product.</p><p>At the same time, the Core Spine remains correct and should be preserved:</p><ul><li>canonical identity</li><li>archive-first registration</li><li>lineage continuity</li><li>modular domains</li><li>applications as delivery surfaces rather than schema owners</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>QiOS adopts a <strong>Single-Account Modular Mode</strong> for the current implementation.</p><h3 id="_1-runtime-mode" tabindex="-1">1. Runtime mode <a class="header-anchor" href="#_1-runtime-mode" aria-label="Permalink to &quot;1. Runtime mode&quot;">​</a></h3><p>The active runtime is <strong>single-account / user-scoped</strong>, not multi-tenant.</p><h3 id="_2-ownership-model" tabindex="-1">2. Ownership model <a class="header-anchor" href="#_2-ownership-model" aria-label="Permalink to &quot;2. Ownership model&quot;">​</a></h3><p>For current domain-scoped records, <code>tenant_id</code> is replaced by <code>owner_user_id</code> referencing <code>auth.users(id)</code>.</p><h3 id="_3-platform-simplification" tabindex="-1">3. Platform simplification <a class="header-anchor" href="#_3-platform-simplification" aria-label="Permalink to &quot;3. Platform simplification&quot;">​</a></h3><p>The following <code>qione</code> concerns are deferred from the active runtime:</p><ul><li>tenants</li><li>tenant membership</li><li>tenant role mapping</li><li>tenant module assignment</li><li>tenant-scoped access resolution</li></ul><p><code>qione</code> is no longer required as the active container model for the first working app.</p><h3 id="_4-module-model" tabindex="-1">4. Module model <a class="header-anchor" href="#_4-module-model" aria-label="Permalink to &quot;4. Module model&quot;">​</a></h3><p>Modules remain valid, but are redefined as:</p><ul><li>domain packages</li><li>navigation surfaces</li><li>optional user-level feature flags or app-level config</li></ul><p>Modules do <strong>not</strong> require tenant infrastructure.</p><h3 id="_5-preserved-architecture" tabindex="-1">5. Preserved architecture <a class="header-anchor" href="#_5-preserved-architecture" aria-label="Permalink to &quot;5. Preserved architecture&quot;">​</a></h3><p>The following remain mandatory:</p><ul><li>one canonical identity per object</li><li>one canonical schema home per concern</li><li>archive registration before advanced automation</li><li>derived layers remain non-canonical</li><li>applications do not redefine business logic or schema truth</li></ul><h3 id="_6-future-compatibility" tabindex="-1">6. Future compatibility <a class="header-anchor" href="#_6-future-compatibility" aria-label="Permalink to &quot;6. Future compatibility&quot;">​</a></h3><p>Multi-tenancy is <strong>deferred</strong>, not rejected. If later required, the system may introduce an account/container layer above user-owned records through a future ADR and migration plan.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>faster implementation</li><li>simpler RLS</li><li>fewer joins</li><li>simpler auth resolution</li><li>easier debugging</li><li>modules can ship independently</li></ul><h3 id="tradeoffs" tabindex="-1">Tradeoffs <a class="header-anchor" href="#tradeoffs" aria-label="Permalink to &quot;Tradeoffs&quot;">​</a></h3><ul><li>no shared tenant workspace model yet</li><li>no org-level RBAC yet</li><li>future collaboration features require later migration</li></ul><h3 id="implementation-rule-changes" tabindex="-1">Implementation rule changes <a class="header-anchor" href="#implementation-rule-changes" aria-label="Permalink to &quot;Implementation rule changes&quot;">​</a></h3><p>Replace:</p><ul><li>&quot;All domain tables must carry <code>tenant_id</code>&quot;</li></ul><p>With:</p><ul><li>&quot;All user-scoped domain tables must carry <code>owner_user_id</code>&quot;</li></ul><p>Replace:</p><ul><li>&quot;Cross-band data access must go through Platform RBAC&quot;</li></ul><p>With:</p><ul><li>&quot;Current runtime access is enforced through <code>auth.uid()</code> ownership policies; any future shared-container access model requires a new ADR.&quot;</li></ul><h2 id="follow-up-actions" tabindex="-1">Follow-up actions <a class="header-anchor" href="#follow-up-actions" aria-label="Permalink to &quot;Follow-up actions&quot;">​</a></h2><ol><li>Update docs that describe the active runtime as multi-tenant.</li><li>Mark hosted multi-tenant portal language as future-state only.</li><li>Update schema guidance from <code>tenant_id</code> to <code>owner_user_id</code> for current implementation.</li><li>Simplify RLS examples accordingly.</li><li>Create migration files for active domain schemas.</li></ol>',43)])])}const p=a(r,[["render",n]]);export{h as __pageData,p as default};
